codeExercises.solution:
const users = [
  { id: 1, name: 'Alice', address: { city: 'Hanoi' } },
  { id: 2, name: 'Bob' }
];

function getUserCity(userId) {
  const user = users.find(u => u.id === userId);

  // Cách 1: Dùng if check
  // if (!user || !user.address) {
  //   return "City not found";
  // }
  // return user.address.city;

  // Cách 2: Dùng Optional Chaining (?.)
  return user?.address?.city || "City not found";
}

// Test case 1 (Hoạt động tốt):
console.log(getUserCity(1)); // Hanoi

// Test case 2 (Đã sửa):
console.log(getUserCity(2)); // City not found

// Test case 3 (Đã sửa):
console.log(getUserCity(3)); // City not found

