function updateCardOrder(column, newCardOrderIds) {
  // Hàm này nhận vào một object column và một mảng id mới
  // và được cho là sẽ trả về một object column đã được cập nhật
  column.cardOrderIds = newCardOrderIds;
  return { column }; // Lỗi logic nằm ở đây
}

